#include <stdio.h>
#include <stdlib.h>

int main() {
    int age = 25;
    double price = 19.99;
    char name[] = "Ahmet";
    char grade = 'A';

    printf("Isim: %s\n", name);
    printf("Yas: %d\n", age);
    printf("Fiyat: %.2f\n", price);
    printf("Not: %c\n", grade);

    // Tip donusumu
    int parsedAge = atoi("30");
    double parsedPrice = atof("9.5");

    printf("\nDonusturulen yas: %d\n", parsedAge);
    printf("Donusturulen fiyat: %.2f\n", parsedPrice);

    // const kullanimi
    const double PI = 3.14159;
    printf("\nPi sayisi: %.5f\n", PI);

    // long ve unsigned
    long bigNumber = 10000000000L;
    unsigned int positiveOnly = 42;
    printf("\nBuyuk sayi: %ld\n", bigNumber);
    printf("Pozitif sayi: %u\n", positiveOnly);

    return 0;
}
